import math

class Solution(object):
    def countPermutations(self, complexity):
        MOD = 10**9 + 7
        # Computer 0 must be unlocked first (root).
        # For any other computer i to be unlockable, there must exist j < i with complexity[j] < complexity[i].
        # Computer 0 must have strictly minimum complexity (otherwise some computer can't be unlocked by 0).
        # If complexity[0] is not strictly less than all others, return 0.
        # If complexity[0] IS strictly minimum, then all other computers can be done in any order: (n-1)! ways.
        c0 = complexity[0]
        for i in range(1, len(complexity)):
            if complexity[i] <= c0:
                return 0
        return math.factorial(len(complexity) - 1) % (10**9 + 7)
